+  const record: AtomicRecord = {
+    name,
+    selector: undefined as unknown as Selector,
+    dependencies: new Map(),
+    selectorDependencies: new Set(),
+    dependents: new Set(),
+    values: new Map(),
+    selectorValues: new Map(),
