+function wrapAtomicValue(value: any, path: string | undefined, track: (dependency: AtomicDependency) => void): any {
+  if (!path || value === null || (typeof value !== 'object' && typeof value !== 'function') || typeof Proxy === 'undefined') {
+    return value
+  }
