+  return new Proxy(value, {
+    get(target, property, receiver) {
+      if (target instanceof Map) {
+        if (property === 'get') {
+          return (key: any) => {
+            const name = `${path}.map:${String(key)}`
+            leaf(name, () => target.get(key))
+            return wrapAtomicValue(target.get(key), name, track)
+          }
+        }
+        if (property === 'has') {
+          return (key: any) => {
+            const name = `${path}.map:${String(key)}`
+            leaf(name, () => target.has(key))
+            return target.has(key)
+          }
+        }
+        return (target as any)[property as any]
+      }
+      if (target instanceof Set && property === 'has') {
+        return (item: any) => {
+          const name = `${path}.set:${String(item)}`
+          leaf(name, () => target.has(item))
+          return target.has(item)
+        }
+      }
+      if (Array.isArray(target) && property === 'includes') {
+        return (item: any, fromIndex?: number) => {
+          for (let index = fromIndex || 0; index < target.length; index++) {
